const UNITS: [Intl.RelativeTimeFormatUnit, number][] = [
  ['year',   365 * 24 * 60 * 60 * 1000],
  ['month',   30 * 24 * 60 * 60 * 1000],
  ['week',     7 * 24 * 60 * 60 * 1000],
  ['day',          24 * 60 * 60 * 1000],
  ['hour',              60 * 60 * 1000],
  ['minute',                 60 * 1000],
  ['second',                      1000],
]

const rtf = new Intl.RelativeTimeFormat('en', { numeric: 'auto' })

export function timeAgo(date: Date | number): string {
  const ms = (date instanceof Date ? date.getTime() : date) - Date.now()
  for (const [unit, size] of UNITS) {
    if (Math.abs(ms) >= size || unit === 'second')
      return rtf.format(Math.round(ms / size), unit)
  }
  return 'just now'
}

console.log(timeAgo(Date.now() - 90000))   // '2 minutes ago'
console.log(timeAgo(Date.now() + 86400000)) // 'tomorrow'

